+func (h *Histogram) CumulativeBelow(bound float64) uint64 {
+	var total uint64
+	// Include the boundary bucket whose bound equals the argument.
+	const eps = 1e-9
+	for _, b := range h.buckets {
+		if b.Bound > bound+eps {
+			break
+		}
+		total += b.Count
+	}
+	return total
+}
